section.programlisting:
1 #ifndef HDEF_COLLISIONS
2 #define HDEF_COLLISIONS
3 
4 #include "Shapes.h"
5 #include "../Utils/MathUtils.h"
6 
7 namespace Mochi::Physics
8 {
9     inline bool CollidesPointAndPoint(const Point &p1, const Point &p2)
10     {
11         return p1.Position == p2.Position;
12     }
13 
14     inline bool CollidesPointAndLine(const Point &p, const Line &l)
15     {
16         float lineLength = (l.End - l.Position).Distance();
17         float d1 = (p.Position - l.Position).Distance();
18         float d2 = (p.Position - l.End).Distance();
19         return Math::Approx(d1 + d2, lineLength);
20     }
21 
22     inline bool CollidesPointAndCircle(const Point &p, const Circle &c)
23     {
24         return (p.Position - c.Position).Distance() <= c.Radius;
25     }
26 
27     inline bool CollidesPointAndRectangle(const Point &p, const Rectangle &r)
28     {
29         return p.Position.x >= (r.Position.x - r.Extents.x) &&
30                p.Position.x <= (r.Position.x + r.Extents.x) &&
31                p.Position.y >= (r.Position.y - r.Extents.y) &&
32                p.Position.y <= (r.Position.y + r.Extents.y);
33     }
34 
35     inline bool CollidesLineAndLine(const Line &l1, const Line &l2)
36     {
37         float x1 = l1.Position.x;
38         float x2 = l1.End.x;
39         float x3 = l2.Position.x;
40         float x4 = l2.End.x;
41         float y1 = l1.Position.y;
42         float y2 = l1.End.y;
43         float y3 = l2.Position.y;
44         float y4 = l2.End.y;
45         float uA = ((x4 - x3) * (y1 - y3) - (y4 - y3) * (x1 - x3)) / ((y4 - y3) * (x2 - x1) - (x4 - x3) * (y2 - y1));
46         float uB = ((x2 - x1) * (y1 - y3) - (y2 - y1) * (x1 - x3)) / ((y4 - y3) * (x2 - x1) - (x4 - x3) * (y2 - y1));
47         if (uA >= 0 && uA <= 1 && uB >= 0 && uB <= 1)
48         {
49             return true;
50         }
51         else
52         {
53             Point start(l1.Position);
54             Point end(l1.End);
55             return l2.Collides(start) || l2.Collides(end);
56         }
57     }
58 
59     inline bool CollidesLineAndCircle(const Line &l, const Circle &c)
60     {
61         Point lStart = Point(l.Position);
62         Point lEnd = Point(l.End);
63         if (c.Collides(lStart) || c.Collides(lEnd))
64             return true;
65 
66         Vector2f lineVector = l.End - l.Position;
67         float lineLength = lineVector.Distance();
68         float dot = Vector2f::Dot(c.Position - l.Position, lineVector) / (lineLength * lineLength);
69         dot = Math::Clamp01(dot);
70         Point closestPoint = Point(l.Position + (lineVector * dot));
71         return c.Collides(closestPoint);
72     }
73 
74     inline bool CollidesLineAndRectangle(const Line &l, const Rectangle &r)
75     {
76         Line other = Line(r.Position + Vector2f(r.Extents.x, r.Extents.y), r.Position + Vector2f(r.Extents.x, -r.Extents.y));
77         if (l.Collides(other))
78             return true;
79         other = Line(r.Position + Vector2f(-r.Extents.x, r.Extents.y), r.Position + Vector2f(r.Extents.x, r.Extents.y));
80         if (l.Collides(other))
81             return true;
82         other = Line(r.Position + Vector2f(-r.Extents.x, r.Extents.y), r.Position + Vector2f(-r.Extents.x, -r.Extents.y));
83         if (l.Collides(other))
84             return true;
85         other = Line(r.Position + Vector2f(-r.Extents.x, -r.Extents.y), r.Position + Vector2f(r.Extents.x, -r.Extents.y));
86         if (l.Collides(other))
87             return true;
88 
89         return false;
90     }
91 
92     inline bool CollidesCircleAndCircle(const Circle &c1, const Circle &c2)
93     {
94         return (c1.Position - c2.Position).Distance() < c1.Radius + c2.Radius;
95     }
96 
97     inline bool CollidesCircleAndRectangle(const Circle &c, const Rectangle &r)
98     {
99         Vector2f test = c.Position;
100 
101         if (c.Position.x < r.Position.x - r.Extents.x)
102             test.x = r.Position.x - r.Extents.x;
103         else if (c.Position.x > r.Position.x + r.Extents.x)
104             test.x = r.Position.x + r.Extents.x;
105 
106         if (c.Position.y < r.Position.y - r.Extents.y)
107             test.y = r.Position.y - r.Extents.y;
108         else if (c.Position.y > r.Position.y + r.Extents.y)
109             test.y = r.Position.y + r.Extents.y;
110 
111         float distance = (c.Position - test).Distance();
112         return distance <= c.Radius;
113     }
114 
115     inline bool CollidesRectangleAndRectangle(const Rectangle &r1, const Rectangle &r2)
116     {
117         return (r1.Position.x + r1.Extents.x >= r2.Position.x - r2.Extents.x &&
118                 r1.Position.x - r1.Extents.x <= r2.Position.x + r2.Extents.x &&
119                 r1.Position.y + r1.Extents.y >= r2.Position.y - r2.Extents.y &&
120                 r1.Position.y - r1.Extents.y <= r2.Position.y + r2.Extents.y);
121     }
122 }
123 
124 #endif
